const item = $input.first().json;
const alert = $('Webhook Alerta Wazuh').first().json.body;

// Campos principales de la alerta
const level = parseInt(alert?.rule?.level ?? 0);
const description = alert?.rule?.description ?? 'Regla desconocida';
const agentName = alert?.agent?.name ?? 'desconocido';
const agentIp = alert?.agent?.ip ?? 'N/A';
const srcIp = alert?.data?.srcip ?? null;
const dstUser = alert?.data?.dstuser ?? null;
const srcUser = alert?.data?.srcuser ?? null;
const command = alert?.data?.command ?? null;
const groups = Array.isArray(alert?.rule?.groups) ? alert.rule.groups.join(', ') : (alert?.rule?.groups ?? 'N/A');
const ruleId = alert?.rule?.id ?? 'N/A';
const location = alert?.location ?? 'N/A';
const rawTs = alert?.timestamp ?? new Date().toISOString();
const tz = item.timezone ?? 'Europe/Madrid';
const ts = new Date(rawTs).toLocaleString('es-ES', { timeZone: tz, hour12: false });
const isCritical = level >= (item.criticalLevel ?? 12);

// ============================================================
// PERSONALIZA ESTO: Bloque de contexto de infraestructura
// Sustituye el EJEMPLO de abajo con los detalles de TU entorno.
// Cuanto más específico (hostnames, servicios, patrones normales),
// mejor será el análisis del LLM. Mantén la etiqueta inicial
// "Contexto de infraestructura" para que el modelo la reconozca.
// ============================================================
const infraContext = `Contexto de infraestructura (EJEMPLO - sustitúyelo con el tuyo propio):
- Clúster de 3 nodos: node-a (10.0.0.10, principal), node-b (10.0.0.11), node-c (10.0.0.12)
- Servicios clave: vector-db (10.0.0.20), postgres (10.0.0.21), servidor de automatización / n8n (10.0.0.22), siem / wazuh (10.0.0.30)
- Borde: malla VPN WireGuard para administración, Cloudflare Tunnel para servicios externos selectivos
- Subred interna: 10.0.0.0/24, solo webhooks de n8n accesibles desde internet público
- Respuesta activa DESACTIVADA, solo monitorización, sin bloqueo automático`;
// ============================================================
// FIN PERSONALIZA ESTO
// ============================================================

const systemPrompt = `Eres un analista de seguridad revisando una alerta del SIEM Wazuh. Responde SOLO con un objeto JSON válido, sin texto fuera del JSON, sin bloques de código markdown.

${infraContext}

Esquema de respuesta (todos los campos son obligatorios):
{
  "risk_level": "low|medium|high|critical",
  "likely_cause": "una frase, la explicación más probable dada esta infraestructura específica",
  "is_likely_false_positive": true o false,
  "fp_reason": "si es falso positivo, breve razón; si no, cadena vacía",
  "recommended_action": ["acción 1", "acción 2"],
  "investigate_commands": ["comando bash 1", "comando bash 2"]
}`;

const userPrompt = `Analiza esta alerta de Wazuh:

Host: ${agentName} (${agentIp})
ID Regla: ${ruleId} | Nivel: ${level}
Descripción: ${description}
Grupos: ${groups}
IP Origen: ${srcIp ?? 'N/A'}
Usuario Destino: ${dstUser ?? 'N/A'} | Usuario Origen: ${srcUser ?? 'N/A'}
Comando: ${command ?? 'N/A'}
Ubicación (fichero de log): ${location}
Fecha y hora: ${ts}

JSON completo de la alerta:
${JSON.stringify(alert, null, 2)}`;

const claudeBodyObj = {
  model: item.claudeModel ?? 'claude-haiku-4-5-20251001',
  max_tokens: 700,
  system: systemPrompt,
  messages: [{ role: 'user', content: userPrompt }]
};

return [{
  json: {
    minAlertLevel: item.minAlertLevel,
    criticalLevel: item.criticalLevel,
    timezone: item.timezone,
    claudeModel: item.claudeModel,
    telegramBotToken: item.telegramBotToken,
    telegramChatId: item.telegramChatId,
    level, description, agentName, agentIp, srcIp, dstUser, srcUser, command, groups, ruleId, location, ts, isCritical,
    claudeBodyObj
  }
}];
